/** biome-ignore-all lint/a11y/useValidAnchor: intentional anchor usage for form preview */
import { Flex } from '@chakra-ui/react';
import { ActionPageDetailFormValues, ActionPageFinancePreset } from '@domain/actionPages';
import { SourceFrequency } from '@domain/entry';
import { IProduct } from '@domain/product';
import { useGetAccount } from '@state/accounts';
import { useGetAllFundsIncludingIncoming } from '@state/funds/helpers';
import { DonationSelector } from '@ui/components/organisms/Funds';
import { formatCurrency, getContrastColor, getShadeColor } from '@ui/utils';
import { getFundSelections } from '@utils';
import currency from 'currency.js';
import { useCallback, useEffect, useMemo, useState } from 'react';
import { useFormContext } from 'react-hook-form';
import { useTranslation } from 'react-i18next';
import { generatePath, useNavigate } from 'react-router-dom';
import { useConfigurationStore } from '../../../contexts/ConfigurationContext';
import { EditorBlockContainer } from '../EditorBlockContainer';

type Props = {
  frequencies: SourceFrequency[];
  futurePledgeSelected: boolean;
  otherAmount?: string;
  selectedAmount?: ActionPageFinancePreset | null;
  selectedFrequency: SourceFrequency;
  setFuturePledgeSelected: (val: boolean) => void;
  setOtherAmount: (val: string | undefined) => void;
  setSelectedAmount?: (amount: ActionPageFinancePreset | null) => void;
  setSelectedFrequency: (frequency: SourceFrequency) => void;
};

export const FinanceBlockPreview = ({
  frequencies,
  futurePledgeSelected,
  otherAmount,
  selectedAmount,
  selectedFrequency,
  setFuturePledgeSelected,
  setOtherAmount,
  setSelectedAmount,
  setSelectedFrequency,
}: Props) => {
  const { t } = useTranslation('actionPagesBuilder');
  const { currentAccount } = useGetAccount();
  const { watch } = useFormContext<ActionPageDetailFormValues>();
  const actionPageId = watch('id');
  const { funds } = useGetAllFundsIncludingIncoming();
  const navigate = useNavigate();
  const formFundSelections = watch('fundConfiguration.fundSelectionsAttributes');
  const amountPresetsOther = watch('amountConfiguration.amountPresetsOther');
  const multiFundExpanded = watch('fundConfiguration.multiFundExpanded');
  const multiFundModifiable = watch('fundConfiguration.multiFundModifiable');
  const fundGroups = watch('fundConfiguration.fundGroupsAttributes');
  const actionButtonBgColor = watch('designConfiguration.actionElementColorPrimary');
  const actionButtonTextColor = getContrastColor(actionButtonBgColor);
  const actionButtonHoverBgColor = getShadeColor(actionButtonBgColor, -20);
  const allowModificationsOfFunds = watch('fundConfiguration.multiFundModifiable');
  const isGoaaEnabled = watch('goaaEnabled');
  const goaaMinimumAmount = watch('goaaMinimumAmount');
  const productPositions = watch('productPositionsAttributes');
  const recurringMessage = watch('amountConfiguration.recurringMessage');
  const displayFrequencyAsCheckbox = watch('amountConfiguration.displayFrequencyAsCheckbox');
  const editing = useConfigurationStore((state) => state.editing);

  const products = watch('products')
    ?.slice()
    .sort(
      (a, b) =>
        (productPositions?.find((pos) => pos.productId === a.id)?.position ?? 0) -
        (productPositions?.find((pos) => pos.productId === b.id)?.position ?? 0)
    );

  const productsForRecurringOnly = watch('productsForRecurringOnly');
  const goaaForceSelection = watch('goaaForceSelection');

  const amounts = watch('amountConfiguration.amountPresets.default')?.map((amount) => {
    const value = currency(amount.amount!);

    return { ...amount, amount: formatCurrency(value.intValue, { hideDecimal: true }) };
  });

  const selectedFunds = getFundSelections(funds, formFundSelections, true).filter(
    (f) => !f._destroy
  );
  const additionalFunds = multiFundModifiable
    ? getFundSelections(funds, formFundSelections, false).filter((f) => !f._destroy)
    : [];

  const [selectedProduct, setSelectedProduct] = useState<IProduct | null | undefined>(null);

  const showFinancePanel = useCallback(() => {
    const accountId = currentAccount?.id;

    if (!accountId || !actionPageId) {
      return;
    }

    navigate({
      pathname: generatePath('/accounts/:accountId/action_pages/:actionPageId/edit/finance', {
        accountId,
        actionPageId,
      }),
    });
  }, [currentAccount?.id, actionPageId, navigate]);

  // Campaign Parity: previously, we forced display of Other Amount if Amount Presets
  // were disabled. Allow Other Amount config to help drive Other Amount display.
  const [showOtherInput, setShowOtherInput] = useState(
    (amounts ?? []).length === 0 && !!amountPresetsOther
  );

  useEffect(() => {
    setShowOtherInput((amounts ?? []).length === 0 && !!amountPresetsOther);
  }, [amounts, amountPresetsOther]);

  const futurePledgeDateValue = watch('amountConfiguration.futurePledgeDate');

  const futurePledgeDate = useMemo(
    () =>
      futurePledgeDateValue instanceof Date
        ? futurePledgeDateValue?.toISOString()
        : futurePledgeDateValue,
    [futurePledgeDateValue]
  );

  const futurePledgeMessage = watch('amountConfiguration.futurePledgeMessage');
  console.log('FinanceBlockPreview', amounts);

  return (
    <EditorBlockContainer
      id="preview-block-finance"
      label={t('finance')}
      onEdit={editing ? undefined : showFinancePanel}
    >
      <Flex margin="auto" maxWidth="448px">
        <DonationSelector
          actionButtonBgColor={actionButtonBgColor}
          actionButtonHoverBgColor={actionButtonHoverBgColor}
          actionButtonTextColor={actionButtonTextColor}
          additionalFunds={additionalFunds}
          allowModificationsOfFunds={allowModificationsOfFunds}
          amountAllocations={[]}
          amountPresetsOther={amountPresetsOther}
          amounts={amounts}
          displayFrequencyAsCheckbox={displayFrequencyAsCheckbox}
          frequencies={frequencies}
          fundGroups={fundGroups ?? []}
          funds={selectedFunds}
          futurePledgeDate={futurePledgeDate}
          futurePledgeMessage={futurePledgeMessage}
          futurePledgeSelected={futurePledgeSelected}
          goaaEnabled={isGoaaEnabled}
          goaaForceSelection={goaaForceSelection}
          minimumGiftAmount={(goaaMinimumAmount || 0) * 100}
          multiFundExpanded={multiFundExpanded}
          otherAmount={otherAmount}
          products={isGoaaEnabled ? products : undefined}
          productsForRecurringOnly={productsForRecurringOnly}
          recurringMessage={recurringMessage}
          selectedAmount={
            selectedAmount ? amounts?.find((a) => a.id === selectedAmount.id) : undefined
          }
          selectedFrequency={selectedFrequency}
          selectedProduct={selectedProduct}
          setAllocationAmount={() => {}}
          setFuturePledgeSelected={setFuturePledgeSelected}
          setOtherAmount={setOtherAmount}
          setSelectedAmount={setSelectedAmount!}
          setSelectedFrequency={setSelectedFrequency}
          setSelectedProduct={setSelectedProduct}
          setShowOtherInput={setShowOtherInput}
          showOtherInput={showOtherInput}
        />
      </Flex>
    </EditorBlockContainer>
  );
};

