const useConfiguration = <T extends FieldValues>({
  formValues,
  key,
}: {
  formValues?: T;
  key: ConfigurationKey;
}) => {
  const [onLoaded, onLoading] = useConfigurationStore((state) => [state.onLoaded, state.onLoading]);
  const { getValues, setValue } = useFormContext<ActionPageDetailFormValues>();

  // Loading state
  useEffect(() => {
    if (formValues) {
      onLoaded(key);
    } else {
      onLoading(key);
    }
  }, [key, formValues, onLoaded, onLoading]);

  // Load data into form - run initially and when server returns new data
  useEffect(() => {
    if (formValues) {
      setValueRecursive({ getValues, prefix: key, setValue, values: formValues });
    }
  }, [setValue, getValues, key, formValues]);
};

