import { ActionPageDetailFormValues, ActionPageFinancePreset } from '@domain/actionPages';
import { SourceFrequency } from '@domain/entry';
import { useGetAllFundsIncludingIncoming } from '@state/funds/helpers';
import { useEnhancedForm } from '@ui/components/formControls/Form';
import { DonationSelector } from '@ui/components/organisms/Funds';
import { formatCurrency } from '@ui/utils';
import { getFundSelections } from '@utils';
import currency from 'currency.js';
import { useMemo, useState } from 'react';
import { FormProvider, useFormContext } from 'react-hook-form';

export const LiveFinancePreview = () => {
  const { funds } = useGetAllFundsIncludingIncoming();
  const { watch } = useFormContext<ActionPageDetailFormValues>();
  const formFundSelections = watch('fundConfiguration.fundSelectionsAttributes');
  const amountPresetsOther = watch('amountConfiguration.amountPresetsOther');
  const multiFundExpanded = watch('fundConfiguration.multiFundExpanded');
  const multiFundModifiable = watch('fundConfiguration.multiFundModifiable');
  const fundGroups = watch('fundConfiguration.fundGroupsAttributes');

  const amounts = watch('amountConfiguration.amountPresets.default')?.map((amount) => ({
    ...amount,
    amount: formatCurrency(currency(amount.amount!).intValue, { hideDecimal: true }),
  }));

  const selectedFunds = getFundSelections(funds, formFundSelections, true).filter(
    (f) => !f._destroy
  );

  const additionalFunds = multiFundModifiable
    ? getFundSelections(funds, formFundSelections, false).filter((f) => !f._destroy)
    : [];

  const formRecurringOptions = watch('amountConfiguration.recurringOptions');
  const goaaEnabled = watch('goaaEnabled');
  const goaaMinimumAmount = watch('goaaMinimumAmount');
  const productsForRecurringOnly = watch('productsForRecurringOnly');
  const goaaForceSelection = watch('goaaForceSelection');
  const recurringMessage = watch('amountConfiguration.recurringMessage');

  const frequencies = useMemo(
    () => formRecurringOptions?.map((option) => option) || [],
    [formRecurringOptions]
  );

  const [selectedFrequency, setSelectedFrequency] = useState<SourceFrequency>(frequencies[0]);
  const [selectedAmount, setSelectedAmount] = useState<ActionPageFinancePreset | null>(null);
  const [otherAmount, setOtherAmount] = useState<string>();

  const form = useEnhancedForm({ initialValues: { email: '', name: '' } });
  const [, setShowOtherInput] = useState<boolean>(false);

  const futurePledgeDateValue = watch('amountConfiguration.futurePledgeDate');

  const futurePledgeDate = useMemo(
    () =>
      futurePledgeDateValue instanceof Date
        ? futurePledgeDateValue?.toISOString()
        : futurePledgeDateValue,
    [futurePledgeDateValue]
  );

  const futurePledgeMessage = watch('amountConfiguration.futurePledgeMessage');

  return (
    <FormProvider {...form}>
      <DonationSelector
        additionalFunds={additionalFunds}
        amountAllocations={[]}
        amountPresetsOther={amountPresetsOther}
        amounts={amounts}
        frequencies={frequencies}
        fundGroups={fundGroups ?? []}
        funds={selectedFunds}
        futurePledgeDate={futurePledgeDate}
        futurePledgeMessage={futurePledgeMessage}
        goaaEnabled={goaaEnabled}
        goaaForceSelection={goaaForceSelection}
        minimumGiftAmount={(goaaMinimumAmount || 0) * 100}
        multiFundExpanded={multiFundExpanded}
        otherAmount={otherAmount}
        productsForRecurringOnly={productsForRecurringOnly}
        recurringMessage={recurringMessage}
        selectedAmount={
          selectedAmount ? amounts?.find((a) => a.id === selectedAmount.id) : undefined
        }
        selectedFrequency={selectedFrequency}
        setOtherAmount={setOtherAmount}
        setSelectedAmount={setSelectedAmount}
        setSelectedFrequency={setSelectedFrequency}
        setShowOtherInput={setShowOtherInput}
      />
    </FormProvider>
  );
};

